{
  "@context": "https://schema.org",
  "@type": "FAQPage",
  "mainEntity": [
    {
      "@type": "Question",
      "name": "How many days can you spend in Arizona before being presumed a resident?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Up to nine months in the aggregate during the tax year. Spending more than nine months in Arizona, roughly 270 days, creates a rebuttable presumption that you are an Arizona resident. It is a presumption, not an automatic rule, so it can be overcome with evidence that you were in the state only for a temporary or transitory purpose."
      }
    },
    {
      "@type": "Question",
      "name": "Can the Arizona nine-month presumption be rebutted?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Yes. The presumption may be overcome by competent evidence that the individual is in Arizona for a temporary or transitory purpose. The day count shifts the burden onto you, but it does not by itself make residency final."
      }
    },
    {
      "@type": "Question",
      "name": "What counts as time spent in Arizona for the nine-month rule?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "The statute looks at time spent in the aggregate across the whole taxable year, so periods do not need to be consecutive. Roughly 270 days, or more than nine months of the year, is the point at which the presumption of residency arises."
      }
    }
  ]
}

