{
  "@context": "https://schema.org",
  "@type": "FAQPage",
  "mainEntity": [
    {
      "@type": "Question",
      "name": "How many days can you stay in Australia without becoming a tax resident?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Fewer than 183 days in an income year keeps you outside the 183-day test. At 183 days or more you are presumed to be a resident for that income year, unless the Commissioner is satisfied that your usual place of abode is outside Australia and you do not intend to take up residence here. The days do not need to be consecutive."
      }
    },
    {
      "@type": "Question",
      "name": "Is Australia's 183-day test based on the calendar year?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "No. Australia's income year runs from 1 July to 30 June, and the days present are added up across that window rather than the calendar year. The count resets each new income year on 1 July, and days do not need to be consecutive to reach 183."
      }
    },
    {
      "@type": "Question",
      "name": "Does 183 days automatically make you an Australian tax resident?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Not automatically. The 183-day test is one of several residency tests the ATO applies, alongside the resides test, the domicile test and the superannuation test. Reaching 183 days creates a presumption of residence, but that presumption is set aside if your usual place of abode is outside Australia and you do not intend to take up residence here."
      }
    }
  ]
}

