{
  "@context": "https://schema.org",
  "@type": "FAQPage",
  "mainEntity": [
    {
      "@type": "Question",
      "name": "How many days can you spend in California without becoming a resident?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "There is no fixed line. California residency is a facts-and-circumstances test based on your closest connections, not a day count. However, spending more than nine months of the tax year in California, roughly 270 days, creates a rebuttable presumption that you are a resident. Fewer than nine months does not presume you are a nonresident."
      }
    },
    {
      "@type": "Question",
      "name": "Does the nine-month presumption automatically make you a California resident?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "No. It is a rebuttable presumption, not an automatic rule. You can overcome it by showing your presence was for a temporary or transitory purpose, but the burden is on you. Conversely, you can be a California resident even if you spend little or no time in the state, if your closest connections are there."
      }
    },
    {
      "@type": "Question",
      "name": "What is a temporary or transitory purpose in California?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "It describes a stay that is not for a settled, permanent connection to California, such as a vacation, a short work assignment, or passing through. If your purpose is temporary or transitory, you are treated as a nonresident even while physically present, whereas a stay for other than a temporary purpose points toward residency."
      }
    }
  ]
}

