{
  "@context": "https://schema.org",
  "@type": "FAQPage",
  "mainEntity": [
    {
      "@type": "Question",
      "name": "How many days can you stay in Canada without becoming a tax resident?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Fewer than 183 days in a calendar year keeps you below the sojourner threshold. If you sojourn in Canada for 183 days or more in a single calendar year, you are deemed to be a resident of Canada for the entire year. The days do not need to be consecutive, and the Canada Revenue Agency counts any part of a day as a day. Note that residential ties such as a home or family in Canada can make you a resident with fewer days."
      }
    },
    {
      "@type": "Question",
      "name": "What is the difference between a deemed resident and a factual resident of Canada?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "A deemed resident is someone without significant residential ties who sojourns in Canada for 183 days or more in a calendar year, under paragraph 250(1)(a) of the Income Tax Act. A factual resident is someone who has established significant residential ties to Canada, such as a home, spouse or common-law partner, or dependants, and can be resident with far fewer days. Both are taxed on worldwide income."
      }
    },
    {
      "@type": "Question",
      "name": "Is Canada's 183-day rule based on the calendar year?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Yes. The sojourner rule counts days present from 1 January to 31 December. The days do not need to be consecutive, and the count resets each new calendar year. If the total reaches 183 or more in one calendar year, you are a deemed resident for that entire year."
      }
    }
  ]
}

