      "@type": "Question",
      "name": "How many days can you stay in Colombia without becoming a tax resident?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Up to 183 calendar days in any 365-day period. Spending more than 183 days in Colombia, continuously or discontinuously, within any window of 365 consecutive calendar days makes you a tax resident. Entry and exit days both count."
      }
    },
    {
      "@type": "Question",
      "name": "Is Colombia's 183-day rule based on the calendar year?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "No. It is measured across any period of 365 consecutive calendar days, not the January-to-December calendar year. When the days straddle two years, you are treated as a resident from the second year."
      }
    },
    {
      "@type": "Question",
      "name": "Do the 183 days in Colombia have to be consecutive?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "No. The days can be continuous or discontinuous. Separate trips are added together, so several shorter stays inside the same 365-day window can combine to cross 183 days."
      }
