{
  "@context": "https://schema.org",
  "@type": "FAQPage",
  "mainEntity": [
    {
      "@type": "Question",
      "name": "How many days can you spend in Colorado without becoming a statutory resident?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Up to six months (183 days) in the tax year. Spending more than six months, roughly 184 days or more, in Colorado while maintaining a permanent place of abode there makes you a statutory resident even if you are domiciled elsewhere. At or under half the year keeps you under the day test."
      }
    },
    {
      "@type": "Question",
      "name": "What counts as a day in Colorado for the six-month rule?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Colorado measures time spent in the state in aggregate across the tax year. Any part of a day present in Colorado generally counts toward the total, and the days do not need to be consecutive. You do not need to sleep at the permanent place of abode for time in the state to count."
      }
    },
    {
      "@type": "Question",
      "name": "Do you need a home in Colorado to be a statutory resident?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Yes. The statutory residence test requires both a permanent place of abode in Colorado and more than six months of the tax year spent there. A permanent place of abode can be a house, condominium, apartment, room, or mobile home, and you need not own or lease it yourself. Days alone, without a qualifying place of abode, do not make you a statutory resident, though separate domicile rules can."
      }
    }
  ]
}

