    {
      "@type": "Question",
      "name": "How many days can you stay in Estonia without becoming a tax resident?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Fewer than 183 days across any period of 12 consecutive calendar months. Reaching 183 days or more within any such 12-month window makes you a tax resident under the day-count test. A separate test also makes you resident if your place of residence is in Estonia."
      }
    },
    {
      "@type": "Question",
      "name": "Is Estonia's 183-day rule based on the calendar year?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "No. It is measured across any period of 12 consecutive calendar months, not the January-to-December calendar year. A stay split across two calendar years can still reach 183 days inside a single 12-month window."
      }
    },
    {
      "@type": "Question",
      "name": "Can you be an Estonian tax resident with fewer than 183 days?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Yes. Estonia also treats you as resident if your place of residence is in Estonia, meaning the place where you permanently or primarily live. The day count is only one of the tests, and meeting either one is enough."
      }
    }
  ]
}

