  "@type": "FAQPage",
  "mainEntity": [
    {
      "@type": "Question",
      "name": "Does Flighty count your days in a country?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "No. Flighty logs the flights you take and builds flight stats, but it does not total how many days you have spent in each country or measure that against a visa or residency limit. Day counting is a separate calculation that uses your flight history as its source."
      }
    },
    {
      "@type": "Question",
      "name": "Can Flighty track the Schengen 90/180 rule?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Not directly. Flighty is a flight tracker, not a visa-limit calculator, so it does not keep a rolling 90/180 Schengen total. You can use your Flighty flight history as the source data and count it against the rule in a day-tracking app."
      }
    },
    {
      "@type": "Question",
      "name": "How do I export my travel history from Flighty?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Flighty can export your flight history to a CSV file, which you can save or share to your device. From there you can open it in a spreadsheet or import it into a day-counting app to turn the flights into dated trips."
      }
    },
    {
      "@type": "Question",
      "name": "Are flights enough to prove residency or visa compliance?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Flight history is strong supporting evidence of when you moved between countries, but it is not complete on its own. It does not capture ground crossings or where you stayed between flights, and official decisions still rest on passport stamps, permits, and authority records."
      }
    }
  ]
}

