  "@type": "FAQPage",
  "mainEntity": [
    {
      "@type": "Question",
      "name": "How many days can you stay in Georgia (the country) without becoming a tax resident?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Fewer than 183 days in any continuous 12-month period. Reaching 183 or more days of actual presence in Georgia within any 12-month window that ends in the tax year makes you a Georgian tax resident for that year under Article 34 of the Tax Code."
      }
    },
    {
      "@type": "Question",
      "name": "Is Georgia's 183-day rule based on the calendar year?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Not exactly. Georgia's tax year is the calendar year, but the 183 days are counted across any continuous 12-month period that ends in that tax year, not strictly from 1 January to 31 December. A stay split across two calendar years can still cross 183 days inside a single 12-month window."
      }
    },
    {
      "@type": "Question",
      "name": "Do all days in Georgia count toward the 183?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Most do, but the Tax Code excludes certain periods from the count, including time in Georgia purely in transit, time spent solely for medical treatment or rest, and days with diplomatic or consular status. Ordinary days of presence for living or working count."
      }
    }
  ]
}

