    {
      "@type": "Question",
      "name": "What is Ireland's 280-day rule?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Even if you are below 183 days in a single year, you are resident for a tax year if your days present in Ireland add up to 280 or more when you combine that year with the year before it. A year in which you spend 30 days or less does not count toward the 280-day total."
      }
    },
    {
      "@type": "Question",
      "name": "How does Ireland count a day of presence?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "You are treated as present in Ireland for a day if you are here for any part of that day. The Irish tax year is the calendar year, so days are totalled from 1 January to 31 December and do not need to be consecutive."
      }
    }
  ]
