{
  "@context": "https://schema.org",
  "@type": "FAQPage",
  "mainEntity": [
    {
      "@type": "Question",
      "name": "How many days can you spend in Maine without becoming a statutory resident?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Up to 183 days in the tax year. Spending 184 days or more in Maine, while maintaining a permanent place of abode there, makes you a statutory resident even if you are domiciled elsewhere. Exactly 183 days keeps you under the day test."
      }
    },
    {
      "@type": "Question",
      "name": "What counts as a permanent place of abode in Maine?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "A house, apartment, or other dwelling you maintain as your home, whether or not you own it. It does not include a seasonal camp or cottage used only for vacations, a hotel or motel room, or a student dormitory room."
      }
    },
    {
      "@type": "Question",
      "name": "Do Maine's safe harbors let you avoid resident status?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Yes. Maine Revenue Services publishes residency safe harbors for people who spend limited time in Maine or keep a permanent home abroad. If you qualify, you can be treated as a nonresident even when the day count would otherwise apply. The two main conditions, a permanent place of abode plus more than 183 days, still define the base rule."
      }
    }
  ]
}

