{
  "@context": "https://schema.org",
  "@type": "FAQPage",
  "mainEntity": [
    {
      "@type": "Question",
      "name": "How many days can you stay in Malta without becoming a tax resident?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Up to 183 days in a calendar year. If you are present in Malta for more than 183 days in a single year, you are treated as a Maltese tax resident for that year, regardless of the purpose of your stay. The days do not need to be consecutive."
      }
    },
    {
      "@type": "Question",
      "name": "Is Malta's 183-day rule based on the calendar year?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Yes. Malta's tax year is the calendar year, and days present are added up across 1 January to 31 December. The count resets each new calendar year, and days do not need to be consecutive to add up to more than 183."
      }
    },
    {
      "@type": "Question",
      "name": "Does becoming a Maltese tax resident mean my worldwide income is taxed?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Not automatically. Residency decides that Malta can tax you; domicile decides how much. An individual who is ordinarily resident and domiciled in Malta is taxed on worldwide income, while a resident who is not domiciled in Malta is generally taxed on Maltese-source income plus foreign income remitted to Malta."
      }
    }
  ]
}

