{
  "@context": "https://schema.org",
  "@type": "FAQPage",
  "mainEntity": [
    {
      "@type": "Question",
      "name": "How many days can you spend in Maryland without becoming a statutory resident?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Up to 182 days in the calendar year. Being physically present in Maryland for 183 days or more, while maintaining a place of abode there for more than six months of the year, makes you a statutory resident even if you are domiciled elsewhere. At 183 days the day test is met."
      }
    },
    {
      "@type": "Question",
      "name": "What counts as a day in Maryland for the 183-day rule?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Any part of a day spent in Maryland counts as a day, though a continuous period of 24 hours or less may not count as more than one day. You do not need to sleep at the place of abode for the day to count."
      }
    },
    {
      "@type": "Question",
      "name": "Do you need a home in Maryland to be a statutory resident?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Yes. The statutory residence test requires both a place of abode maintained for more than six months of the year and 183 or more days of physical presence in Maryland. Days alone, without a qualifying place of abode, do not make you a statutory resident, though separate domicile rules can."
      }
    }
  ]
}

