{
  "@context": "https://schema.org",
  "@type": "FAQPage",
  "mainEntity": [
    {
      "@type": "Question",
      "name": "How many days can you stay in Mauritius without becoming a tax resident?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Fewer than 183 days in a single income year, and you must also stay under the separate 270-day aggregate test. If your days present in Mauritius reach 183 or more in one income year, you are a resident for that year. Even below 183 in the current year, reaching 270 days in aggregate across the current income year and the two preceding ones also makes you a resident. Days do not need to be consecutive."
      }
    },
    {
      "@type": "Question",
      "name": "What is the income year for Mauritius tax residency?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Mauritius uses an income year that runs from 1 July to 30 June, not the calendar year. Days present are added up across that 1 July to 30 June window for the 183-day test, and the 270-day test aggregates days across the current income year and the two income years before it."
      }
    },
    {
      "@type": "Question",
      "name": "What is the 270-day rule in Mauritius?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "It is a second, separate residence test. If your days present in Mauritius add up to 270 or more across the current income year and the two preceding income years, you are a Mauritian tax resident, even if no single year reached 183 days. It catches people who spend substantial but sub-183-day periods in Mauritius year after year."
      }
    }
  ]
}

