{
  "@context": "https://schema.org",
  "@type": "FAQPage",
  "mainEntity": [
    {
      "@type": "Question",
      "name": "How many days can you stay in New Zealand without becoming a tax resident?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Up to 183 days in any 12-month period. Spending more than 183 days in New Zealand within any 12-month window makes you a tax resident, and your residency is backdated to the first of those 183 days. A separate permanent-place-of-abode test can also make you resident with fewer days."
      }
    },
    {
      "@type": "Question",
      "name": "Is New Zealand's 183-day rule based on the tax year?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "No. It is measured across any 12-month period, not the 1 April to 31 March tax year. The days do not need to be consecutive, and stays split across different periods can still add up to more than 183 days inside a single 12-month window."
      }
    },
    {
      "@type": "Question",
      "name": "Can you be a New Zealand tax resident with fewer than 183 days?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Yes. New Zealand also treats you as resident if you have a permanent place of abode there, a place you usually live and can call home, even if you keep a home elsewhere too. The day count is only one of the tests, and residency can end only after being away for more than 325 days in a 12-month period."
      }
    }
  ]
}

