{
  "@context": "https://schema.org",
  "@type": "FAQPage",
  "mainEntity": [
    {
      "@type": "Question",
      "name": "How many contact periods can you have in Ohio without being a presumed resident?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Up to 212 contact periods in the calendar year. Having more than 212 contact periods (213 or more) makes you a presumed Ohio resident. To be presumed a nonresident you must also keep at least one abode outside Ohio for the entire year and file the Affidavit of Non-Ohio Residency."
      }
    },
    {
      "@type": "Question",
      "name": "What is a contact period in Ohio, and how is it different from a day?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "A contact period is essentially an overnight. You have one contact period when you are away overnight from your abode outside Ohio and spend at least some part, however minimal, of each of two consecutive days in Ohio. Unlike an any-part-of-a-day count, a single daytime visit with no overnight does not create a contact period."
      }
    },
    {
      "@type": "Question",
      "name": "Do you have to file anything to be treated as an Ohio nonresident?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Yes. If you have 212 or fewer contact periods and keep an abode outside Ohio all year, you are presumed a nonresident only if you file the Affidavit of Non-Ohio Residency with the Department of Taxation. Missing the affidavit deadline lets Ohio presume you were domiciled in Ohio for the whole year."
      }
    }
  ]
}

