{
  "@context": "https://schema.org",
  "@type": "FAQPage",
  "mainEntity": [
    {
      "@type": "Question",
      "name": "What does 90 days in any 180-day period mean?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "For the Schengen short-stay rule, it means that on each day you are in the Schengen area, you look back 180 days and count all Schengen days inside that moving window. The general short-stay limit is up to 90 total Schengen days inside that 180-day period."
      }
    },
    {
      "@type": "Question",
      "name": "What does 90 days in any 180 day period mean without the hyphen?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "It means the same thing as 180-day period. The hyphen changes the grammar, not the rule: the Schengen limit is still measured across a rolling 180-day lookback."
      }
    },
    {
      "@type": "Question",
      "name": "What is the 90-day rule in Europe?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "People usually mean the Schengen short-stay rule: many non-EU visitors can spend up to 90 total days in the Schengen area within any rolling 180-day period. It is not 90 days per Schengen country and it is not a fixed half-year calendar block."
      }
    },
    {
      "@type": "Question",
      "name": "Does the Schengen 90/180 rule reset after 90 days out?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Not as a lump-sum reset. Days become available when older Schengen stay days fall outside the current 180-day lookback, so availability can return one day at a time."
      }
    }
  ]
}

