{
  "@context": "https://schema.org",
  "@type": "FAQPage",
  "mainEntity": [
    {
      "@type": "Question",
      "name": "What does a single-entry Schengen visa mean?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "A single-entry visa lets you enter the Schengen area once. The moment you leave, the visa is used up, even if unused days of the authorized stay remain and the validity dates have not expired. To return you need a new visa or a multiple-entry visa."
      }
    },
    {
      "@type": "Question",
      "name": "What is the difference between number of entries and duration of stay on a Schengen visa?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "The number of entries (1, 2, or MULT) is how many times you may cross into the Schengen area. The duration of stay is the maximum number of days you may stay, printed in days on the visa. They are separate fields: a single-entry visa can still authorize a stay of up to 90 days, but only for one entry."
      }
    },
    {
      "@type": "Question",
      "name": "Does a Schengen single-entry visa still fall under the 90/180 rule?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Yes. The duration of stay printed on the visa is a maximum, and it operates inside the general short-stay limit of 90 days in any 180-day period. A visa never authorizes more than the days it prints, and never more than the 90/180 allowance permits."
      }
    }
  ]
}

