  "@type": "FAQPage",
  "mainEntity": [
    {
      "@type": "Question",
      "name": "How many days can you stay in Singapore without becoming a tax resident?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Fewer than 183 days in a calendar year. If your days of physical presence or employment in Singapore reach 183 or more in a single year, you are treated as a Singapore tax resident for that year of assessment. The days do not need to be consecutive."
      }
    },
    {
      "@type": "Question",
      "name": "Is Singapore's 183-day rule based on the calendar year?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Yes. Residency is assessed against the calendar year preceding the year of assessment, and the days present are added up across 1 January to 31 December. The count resets each new calendar year, and the days do not need to be consecutive to reach 183."
      }
    },
    {
      "@type": "Question",
      "name": "Can you be a Singapore tax resident with fewer than 183 days in a year?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Yes, under administrative concessions. If you work in Singapore across two calendar years and your total stay is at least 183 days, or you stay or work in Singapore continuously across three straddling calendar years, IRAS treats you as resident for those years even where a single year falls short of 183 days."
      }
    }
  ]
}

