    {
      "@type": "Question",
      "name": "How many days can you stay in Turkiye on a visa or visa exemption?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "At most 90 days within any 180-day period. The length of stay provided by a visa or visa exemption for tourism or business cannot exceed 90 days within each 180 days. The days do not need to be consecutive, and the 180-day window is a rolling one, not a fixed calendar block."
      }
    },
    {
      "@type": "Question",
      "name": "Is Turkiye's 90/180 rule a rolling window or a fixed period?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "It is a rolling window. On any given day you look back over the previous 180 days and add up the days you were in Turkiye. That total must not exceed 90. It is not a 90-in, 90-out reset and not tied to the calendar year, so the window moves forward with you every day."
      }
    },
    {
      "@type": "Question",
      "name": "How do you stay in Turkiye longer than 90 days?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "A visa or visa exemption cannot be extended beyond 90 days in 180. Foreigners who want to stay longer must apply for a Short Term Residence Permit at the Provincial Directorate of Migration Administration. A residence permit takes you out of the 90/180 short-stay limit."
      }
    }
  ]
}

