{
  "@context": "https://schema.org",
  "@type": "FAQPage",
  "mainEntity": [
    {
      "@type": "Question",
      "name": "How many days can you stay in the UAE without becoming a tax resident?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Up to 182 days in any consecutive 12-month period. Reaching 183 days or more of physical presence within any 12-month window makes you a UAE tax resident under the day-count test. Every day, including any part of a day spent in the UAE, counts."
      }
    },
    {
      "@type": "Question",
      "name": "Is the UAE's 183-day rule based on the calendar year?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "No. It is measured across any consecutive 12-month period, not the January-to-December calendar year. A stay split across two calendar years can still reach 183 days inside a single 12-month window."
      }
    },
    {
      "@type": "Question",
      "name": "Can you be a UAE tax resident with fewer than 183 days?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Yes. A 90-day test can make you resident if you are a UAE national, a UAE resident, or a GCC national who has a permanent place of residence in the UAE or a job or business there. You can also qualify if your usual or primary place of residence and centre of financial and personal interests are in the UAE."
      }
    }
  ]
}

