{
  "@context": "https://schema.org",
  "@type": "FAQPage",
  "mainEntity": [
    {
      "@type": "Question",
      "name": "How long can you stay in the US on the Visa Waiver Program?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Up to 90 days per admission. With an approved ESTA, travelers under the Visa Waiver Program may be admitted for up to 90 days per visit. The 90 days is set for each admission, not an annual allowance, and a CBP officer decides the actual period at entry."
      }
    },
    {
      "@type": "Question",
      "name": "Does a trip to Canada or Mexico reset the 90 days?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Generally no. A short trip to Canada, Mexico, or an adjacent island does not restart the clock. When you re-enter, you are usually readmitted only for the balance of your original 90-day period, which continues from your first US admission, unless you are a resident of the country you visited."
      }
    },
    {
      "@type": "Question",
      "name": "Can you extend a Visa Waiver stay or change status?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Generally no. Travelers admitted under the Visa Waiver Program normally cannot extend their stay or change to another immigration status. You are expected to leave within the 90 days you were admitted for."
      }
    }
  ]
}

