{
  "@context": "https://schema.org",
  "@type": "FAQPage",
  "mainEntity": [
    {
      "@type": "Question",
      "name": "How many days can you spend in Vermont without becoming a statutory resident?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Up to 183 days in the taxable year. Spending more than 183 days (184 or more) in Vermont, while maintaining a permanent place of abode there, makes you a statutory resident even if you are domiciled elsewhere. Exactly 183 days keeps you under the day test."
      }
    },
    {
      "@type": "Question",
      "name": "What counts as a day in Vermont for the 183-day rule?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Vermont counts any part of a day spent in the state as a full day, with narrow exceptions. You do not need to sleep at the permanent place of abode for the day to count."
      }
    },
    {
      "@type": "Question",
      "name": "Do you need a home in Vermont to be a statutory resident?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Yes. The statutory residence test requires both a permanent place of abode in Vermont and more than 183 days in the state during the taxable year. Days alone, without a qualifying place of abode, do not make you a statutory resident, though a separate domicile test can."
      }
    }
  ]
}

