{
  "@context": "https://schema.org",
  "@type": "FAQPage",
  "mainEntity": [
    {
      "@type": "Question",
      "name": "How many days can you spend in Virginia without becoming an actual resident?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Up to 183 days in the taxable year. Being physically present or maintaining a place of abode in Virginia for an aggregate of more than 183 days (184 or more) makes you an actual resident even if you are domiciled elsewhere. Exactly 183 days keeps you under the day test."
      }
    },
    {
      "@type": "Question",
      "name": "What counts as a day in Virginia for the 183-day rule?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Any portion of a day in which you are physically present in Virginia counts as a full day, except for part of a day spent solely while in transit to a destination outside Virginia. The days are aggregated across the whole taxable year and do not have to be consecutive."
      }
    },
    {
      "@type": "Question",
      "name": "Does Virginia tax you if you are domiciled in another state?",
      "acceptedAnswer": {
        "@type": "Answer",
        "text": "Yes. Virginia has two kinds of resident: domiciliary residents and actual residents. If you maintain a place of abode in Virginia for more than 183 days in the taxable year, you are an actual resident and taxed by Virginia even though your true, permanent home is in another state or country."
      }
    }
  ]
}

